; ************************************************************************************************
; ************************************************************************************************
;
;		Name:		createfind.asm
;		Purpose:	Create/Find an identifier
;		Created:	11th August 2023
;		Reviewed:	No
;		Author:		Paul Robson (paul@robsons.org.uk)
;
; ************************************************************************************************
; ************************************************************************************************

		.section as16code

; ************************************************************************************************
;
;									Create/Find an identifier YX
; 									  CC = Found, CS = Created
;
; ************************************************************************************************

AXICreateFind:
		stx 	AXTemp1 					; save address at zTemp1
		sty 	AXTemp1+1
		jsr 	AXICalculateHash 			; calculate hash
		;
		lda 	AXIBase 					; start scanning.
		sta 	AXTemp0+1
		stz 	AXTemp0
		jsr 	AXIOpen 					; start.
		;
		;		Find the end, checking for duplicates as we go.
		;
_AXIFindEnd:								; go to the end checking for duplicates.
		lda 	(AXTemp0)
		beq 	_AXIFoundEnd
		jsr 	AXICompareCurrent 			; compare AXTemp1 ident vs AXTemp0 record
		bcc 	_AXICFound 					; it's been found.
		;
		clc 								; go to next
		lda 	(AXTemp0)
		adc 	AXTemp0
		sta 	AXTemp0
		bcc 	_AXIFindEnd
		inc 	AXTemp0+1
		bra 	_AXIFindEnd
		;
		;		AXTemp0 now points at the end (the zero link)
		;
_AXIFoundEnd:
		ldy 	#0
		;
_AXIFill:									; fill +2,3,4,5 with zeros.
		lda 	#0
		sta 	(AXTemp0),y
		iny
		cpy 	#AXID_Identifier
		bne 	_AXIFill
_AXICopy:
		phy
		tya 								; access equivalent character in name.
		sec
		sbc 	#AXID_Identifier
		tay
		lda 	(AXTemp1),y 				; get character and write it out.
		ply
		sta 	(AXTemp0),y
		iny 								; next character
		asl 	a 							; keep going till bit 7 set.
		bcc 	_AXICopy

		lda 	#0 							; write zero at end (end of list)
		sta 	(AXTemp0),y
		;
		tya 								; set the offset link.
		sta 	(AXTemp0)
		;
		ldy 	#AXID_Hash 					; fill the data in. +1 is the hash
		lda 	AXIHash
		sta 	(AXTemp0),y
		;
		ldy 	#AXID_Flags 				; set the undefined flag.
		lda 	#$80
		sta 	(AXTemp0),y
		sec 								; return CS, created
		;
_AXICFound:
		php 								; save carry
		lda 	AXTemp0 					; save as current record
		sta 	AXCurrent
		lda 	AXTemp0+1
		sta 	AXCurrent+1
		jsr 	AXIClose 					; close access
		plp 								; restore carry.
		rts

		.send as16code

; ************************************************************************************************
;
;									Changes and Updates
;
; ************************************************************************************************
;
;		Date			Notes
;		==== 			=====
;
; ************************************************************************************************

; ************************************************************************************************
; ************************************************************************************************
;
;		Name:		getset.asm
;		Purpose:	Access offset data.
;		Created:	11th August 2023
;		Reviewed:	No
;		Author:		Paul Robson (paul@robsons.org.uk)
;
; ************************************************************************************************
; ************************************************************************************************

		.section as16code

; ************************************************************************************************
;
;									Get element Y => A
;
; ************************************************************************************************

AXIGet:
		jsr 	AXIOpen 					; start.

		lda 	AXCurrent 					; copy address for access
		sta 	AXTemp0
		lda 	AXCurrent+1
		sta 	AXTemp0+1

		lda 	(AXTemp0),y 				; read
		jsr 	AXIClose 					; close access

		rts

; ************************************************************************************************
;
;									Get element Y => A
;
; ************************************************************************************************

AXIPut:
		jsr 	AXIOpen 					; start.
		pha
		lda 	AXCurrent 					; copy address for access
		sta 	AXTemp0
		lda 	AXCurrent+1
		sta 	AXTemp0+1
		pla
		sta 	(AXTemp0),y 				; write
		jsr 	AXIClose 					; close access
		rts

; ************************************************************************************************
;
;								Put Data YX to DataLow/High, and set flag
;
;				  Put can *FAIL* if defined and different - a redefinition error.
;
; ************************************************************************************************

AXIPutData:
		jsr 	AXIOpen 					; start.
		lda 	AXCurrent 					; copy address for access
		sta 	AXTemp0
		lda 	AXCurrent+1
		sta 	AXTemp0+1

		phy 								; save Y on stack.
		ldy 	#AXID_Flags
		lda 	(AXTemp0),y 				; check if defined.
		bmi 	_AXIPutOkay 				; no, it is always okay to put.

		pla  								; get MSB back
		pha
		ldy 	#AXID_DataHigh
		cmp 	(AXTemp0),y
		bne 	_AXIPutError 				; if value has changed, that's an error
		txa 								; check LSB
		ldy 	#AXID_DataLow
		cmp 	(AXTemp0),y
		bne 	_AXIPutError 				; if value has changed, that's an error

_AXIPutOkay:
		pla
		ldy 	#AXID_DataHigh 				; write high byte
		sta 	(AXTemp0),y

		txa
		ldy 	#AXID_DataLow 				; write low byte
		sta 	(AXTemp0),y

		ldy 	#AXID_Flags 				; clear the 'defined' flag.
		lda 	(AXTemp0),y
		and 	#$7F
		sta 	(AXTemp0),y

		jsr 	AXIClose 					; close access
		clc
		rts

_AXIPutError:
		pla 								; throw saved Y
		jsr 	AXIClose 					; return with error redefine.
		lda 	#AXERRRedefine
		sec
		rts

		.send as16code

